"use strict";(globalThis.webpackChunkieee_tritonbot_website=globalThis.webpackChunkieee_tritonbot_website||[]).push([[399],{9501(e){e.exports=JSON.parse('{"version":{"pluginId":"docs","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/ieee_tritonbot_website/docs/Tritonbots","label":"TritonBots","docId":"Tritonbots","unlisted":false},{"type":"link","href":"/ieee_tritonbot_website/docs/Introduction","label":"Introduction","docId":"Introduction","unlisted":false}]},"docs":{"Introduction":{"id":"Introduction","title":"Introduction","description":"This year the team has developed the first iteration of the robot with full competition capabilities. Due to team management, leadership issues, poor work quality, and subpar documentation past designs have failed to carry over from previous years. Robot design has been overhauled for more custom hardware that builds on work from other teams\u2019 research and development in the league. A major outcome of this year\u2019s work is custom PCB design and physical analysis of the robot\u2019s functionality for mechanical design. This allowed for reliable operation of our kicker and dribbler. The software for making robot decisions has shifted from traditional programming to a machine learning approach. Following the software shift, the communication protocol to microcontrollers has been simplified, producing a more robust robot hardware control system.","sidebar":"tutorialSidebar"},"Tritonbots":{"id":"Tritonbots","title":"TritonBots","description":"This page will review the v2026 hardware and software changes to the TritonBots RoboCup Small Size League team at the University of California, San Diego. The team intends to compete at RoboCup 2026 in Incheon, South Korea. Changes and new developments to the electronics, mechanical design, AI systems and control systems will be discussed in detail, highlighting the improvements and progression the team has made over the course of the RoboCup 2026 season.","sidebar":"tutorialSidebar"}}}}')}}]);